Temporary variables necessitate garbage collection overhead. The @time macro reveals allocation metrics.






Tip



The initial @time invocation includes JIT compilation overhead. Run twice for accuracy, or use BenchmarkTools and its @btime macro.





function add100_slow!(x)
    for i in 1:100
        x[:] = x .+ 1
    end
    return x
end

data = randn(10^6);
@time add100_slow!(data);

  0.440666 seconds (239.40 k allocations: 774.794 MiB, 55.13% gc time, 16.43% compilation time)


Problems identified:

Many allocations indicate temporary vector creation
High memory consumption
Significant GC time





function add100_fast!(x)
    x .+= 100
end

@time add100_fast!(data);

  0.021665 seconds (109.85 k allocations: 5.465 MiB, 98.60% compilation time)

Create custom HTML rendering for notebooks and Pluto environments:

function Base.show(io::IO, ::MIME"text/html", c::Comic)
    show(io, MIME"text/html"(), HTML("""
       &lt;div&gt;
        &lt;h2&gt;&lt;code&gt;XKCD.Comic&lt;/code&gt; $(c.json["num"]): $(c.json["title"])&lt;/h2&gt;
        &lt;img src="$(c.json["img"])" alt="$(c.json["alt"])" title="$(c.json["alt"])"&gt;
        &lt;div&gt;
          &lt;a href="https://xkcd.com/$(c.json["num"])"&gt;
            Link to Original
          &lt;/a&gt;
        &lt;/div&gt;
      &lt;/div&gt;
    """))
end

